import com.santaba.agent.groovyapi.expect.Expect;
import com.santaba.agent.groovyapi.snmp.Snmp;
import com.santaba.agent.groovyapi.http.*;
import com.santaba.agent.groovyapi.jmx.*;
import org.xbill.DNS.*;
//ADDED MANUALLY
import org.apache.http.client.methods.CloseableHttpResponse
import org.apache.http.client.methods.HttpGet
import org.apache.http.client.methods.HttpPost
import org.apache.http.impl.client.CloseableHttpClient
import org.apache.http.impl.client.HttpClients
import org.apache.http.util.EntityUtils
import javax.net.ssl.X509TrustManager
import javax.net.ssl.TrustManager
import java.security.cert.X509Certificate
import java.security.cert.CertificateException
import javax.net.ssl.HostnameVerifier
import javax.net.ssl.HttpsURLConnection
import javax.net.ssl.SSLContext
import java.security.SecureRandom
import org.apache.http.conn.ssl.NoopHostnameVerifier
import org.apache.http.entity.StringEntity
import org.json.JSONObject
import org.json.JSONArray

// get the host, credentials, and mgmt station baseurl from the device property table
hostname = hostProps.get("system.hostname");
userid = hostProps.get("tegile.user");
passwd = hostProps.get("tegile.pass");
base_url = "https://" + hostname;
//create auth Base64 encryption
auth_raw = userid + ":" + passwd
auth = auth_raw.bytes.encodeBase64().toString()

//init PoolArray
poolArray=[]

// construct the full endpoint url
endpoint_url = base_url + "/zebi/api/v2/listPools"; //LIST POOLS
method = "get"

get_pools = APIrequest(endpoint_url,auth,method)

if (get_pools != 404){
	// iterate over the json_object 
	for (int i=0; i<get_pools.length();i++){
		JSONObject obj = get_pools.get(i);

		pool_name_wildalias = obj.getString("name");
		pool_name_wildvalue = SpecialCharacterCheck(pool_name_wildalias)

		//feed the Pool(s) array
		poolArray.add(pool_name_wildvalue)
	}

	//now we have the pools into an array, we'll need to iterate over that list & pull info for each Pool
	poolArray.each {
		pool_name=it
		pool=pool_name //store the actual Pool (in order to use on the PerformanceCheck, since the pool_name will be overwritten in the POST request)

		// construct the full endpoint url
		endpoint_url = base_url + "/zebi/api/v2/getPoolSpaceInfo"; //GET POOL SPACE INFO
		method = "post"
		post_reply=true
		//request info for the passed Pool
		get_pool_info = APIrequest(endpoint_url,auth,method,'"'+pool_name+'"',post_reply)

		if (get_pool_info != 404){
			// iterate over the json_object 
			for (int i=0; i<get_pool_info.length();i++){
				JSONObject obj = get_pool_info.get(i);

				//extract data from JSON response
				totalPoolSize = obj["totalPoolSize"];
				originalUsedByDataAndSnapshot=obj["originalUsedByDataAndSnapshot"]
				usedByDataAndSnapshot=obj["usedByDataAndSnapshot"]
				compressionSavingsPercentage=obj["compressionSavingsPercentage"]
				dedupeSavingsPercentage=obj["dedupeSavingsPercentage"]
				totalSavingsPercentage=obj["totalSavingsPercentage"]
				usedByAll=obj["usedByAll"]
				available=obj["available"]
				usedByData=obj["usedByData"]
				usedByReservation=obj["usedByReservation"]
				usedBySnapshot=obj["usedBySnapshot"]
				totalMetaSize=obj["totalMetaSize"]
				usedMeta=obj["usedMeta"]

				//print the actual values (for the respective datapoints
				println pool_name+".totalPoolSize="+totalPoolSize
				println pool_name+".originalUsedByDataAndSnapshot="+originalUsedByDataAndSnapshot
				println pool_name+".usedByDataAndSnapshot="+usedByDataAndSnapshot
				println pool_name+".compressionSavingsPercentage="+compressionSavingsPercentage
				println pool_name+".dedupeSavingsPercentage="+dedupeSavingsPercentage
				println pool_name+".totalSavingsPercentage="+totalSavingsPercentage
				println pool_name+".usedByAll="+usedByAll
				println pool_name+".available="+available
				println pool_name+".usedByData="+usedByData
				println pool_name+".usedByReservation="+usedByReservation
				println pool_name+".usedBySnapshot="+usedBySnapshot
				println pool_name+".totalMetaSize="+totalMetaSize
				println pool_name+".usedMeta="+usedMeta
			}
		}

		//get Pool Disks Performance Stats
		endpoint_url = base_url + "/zebi/api/v2/getOneMinuteSystemAnalyticsHistory";
		method = "post"
		pool_name = '["POOL_PERFORMANCE"]'
		post_reply=false

		get_disks_performance = APIrequest(endpoint_url,auth,method,pool_name,post_reply)

		if (get_disks_performance != 404){
			for (int i=0; i<get_disks_performance.length();i++){
				JSONObject obj = get_disks_performance.get(i);

				//according to Tegile there's 4 type of Type (within PoolPerformance)
				//We'll test those 4 & see which ones return data (within each pool)
				try{
					DataType_check = obj["averages"][pool+"/Data/Write_Ops"];
					DataType_check_bool=true
				}catch(Exception exc1){
					DataType_check_bool=false
				}

				try{
					CatcheType_check = obj["averages"][pool+"/Cache/Write_Ops"];
					CatcheType_check_bool=true
				}catch(Exception exc1){
					CatcheType_check_bool=false
				}

				try{
					MetaType_check = obj["averages"][pool+"/Meta/Write_Ops"];
					MetaType_check_bool=true
				}catch(Exception exc1){
					MetaType_check_bool=false
				}

				try{
					IFlashType_check = obj["averages"][pool+"/Iflash/Write_Ops"];
					IFlashType_check_bool=true
				}catch(Exception exc1){
					IFlashType_check_bool=false
				}

				//Since we now know which type of Disks there's (in terms of Pool Performance)
				//Lets grab the different values for each one (if True)
				if(DataType_check_bool==true){
					Read_MBps= obj["averages"][pool+"/Data/Read_MBps"];
					Write_Mbps= obj["averages"][pool+"/Data/Write_MBps"];
					Read_Ops= obj["averages"][pool+"/Data/Read_Ops"];
					Write_Ops= obj["averages"][pool+"/Data/Write_Ops"];
					Read_Latency= obj["averages"][pool+"/Data/Read_Latency"];
					Write_Latency= obj["averages"][pool+"/Data/Write_Latency"];

					println pool+".PerformanceStats.DataDisk.Read_MBps="+Read_MBps
					println pool+".PerformanceStats.DataDisk.Write_MBps="+Write_Mbps
					println pool+".PerformanceStats.DataDisk.Read_Ops="+Read_Ops
					println pool+".PerformanceStats.DataDisk.Write_Ops="+Write_Ops
					println pool+".PerformanceStats.DataDisk.Read_Latency="+Read_Latency
					println pool+".PerformanceStats.DataDisk.Write_Latency="+Write_Latency
				}

				if(CatcheType_check_bool==true){
					Read_MBps= obj["averages"][pool+"/Cache/Read_MBps"];
					Write_Mbps= obj["averages"][pool+"/Cache/Write_MBps"];
					Read_Ops= obj["averages"][pool+"/Cache/Read_Ops"];
					Write_Ops= obj["averages"][pool+"/Cache/Write_Ops"];
					Read_Latency= obj["averages"][pool+"/Cache/Read_Latency"];
					Write_Latency= obj["averages"][pool+"/Cache/Write_Latency"];

					println pool+".PerformanceStats.CacheDisk.Read_MBps="+Read_MBps
					println pool+".PerformanceStats.CacheDisk.Write_MBps="+Write_Mbps
					println pool+".PerformanceStats.CacheDisk.Read_Ops="+Read_Ops
					println pool+".PerformanceStats.CacheDisk.Write_Ops="+Write_Ops
					println pool+".PerformanceStats.CacheDisk.Read_Latency="+Read_Latency
					println pool+".PerformanceStats.CacheDisk.Write_Latency="+Write_Latency
				}

				if(MetaType_check_bool==true){
					Read_MBps= obj["averages"][pool+"/Meta/Read_MBps"];
					Write_Mbps= obj["averages"][pool+"/Meta/Write_MBps"];
					Read_Ops= obj["averages"][pool+"/Meta/Read_Ops"];
					Write_Ops= obj["averages"][pool+"/Meta/Write_Ops"];
					Read_Latency= obj["averages"][pool+"/Meta/Read_Latency"];
					Write_Latency= obj["averages"][pool+"/Meta/Write_Latency"];

					println pool+".PerformanceStats.MetaDisk.Read_MBps="+Read_MBps
					println pool+".PerformanceStats.MetaDisk.Write_MBps="+Write_Mbps
					println pool+".PerformanceStats.MetaDisk.Read_Ops="+Read_Ops
					println pool+".PerformanceStats.MetaDisk.Write_Ops="+Write_Ops
					println pool+".PerformanceStats.MetaDisk.Read_Latency="+Read_Latency
					println pool+".PerformanceStats.MetaDisk.Write_Latency="+Write_Latency
				}

				if(IFlashType_check_bool==true){
					Read_MBps= obj["averages"][pool+"/Iflash/Read_MBps"];
					Write_Mbps= obj["averages"][pool+"/Iflash/Write_MBps"];
					Read_Ops= obj["averages"][pool+"/Iflash/Read_Ops"];
					Write_Ops= obj["averages"][pool+"/Iflash/Write_Ops"];
					Read_Latency= obj["averages"][pool+"/Iflash/Read_Latency"];
					Write_Latency= obj["averages"][pool+"/Iflash/Write_Latency"];

					println pool+".PerformanceStats.IflashDisk.Read_MBps="+Read_MBps
					println pool+".PerformanceStats.IflashDisk.Write_MBps="+Write_Mbps
					println pool+".PerformanceStats.IflashDisk.Read_Ops="+Read_Ops
					println pool+".PerformanceStats.IflashDisk.Write_Ops="+Write_Ops
					println pool+".PerformanceStats.IflashDisk.Read_Latency="+Read_Latency
					println pool+".PerformanceStats.IflashDisk.Write_Latency="+Write_Latency
				}
			} 
		}

		//get Pool Performance Stats
		endpoint_url = base_url + "/zebi/api/v2/getOneMinuteDataAnalyticsHistory";
		method = "post"
		pool_name = '["'+pool+'"],null,null'
		post_reply=false

		get_pool_performance = APIrequest(endpoint_url,auth,method,pool_name,post_reply)

		if (get_pool_performance != 404){
			for (int i=0; i<get_pool_performance.length();i++){
				JSONObject obj = get_pool_performance.get(i);

				Read_MBps = obj["averages"]["Read_MBps"]
				Write_MBps = obj["averages"]["Write_MBps"]
				Total_MBps = obj["averages"]["Total_MBps"]
				Read_Ops = obj["averages"]["Read_Ops"]
				Write_Ops = obj["averages"]["Write_Ops"]
				Total_Ops = obj["averages"]["Total_Ops"]
				Read_Latency = obj["averages"]["Read_Latency"]
				Write_Latency = obj["averages"]["Write_Latency"]
				Average_Latency = obj["averages"]["Average_Latency"]


				println pool+".PerformanceStats.Pool.Read_MBps="+Read_MBps
				println pool+".PerformanceStats.Pool.Write_MBps="+Write_MBps
				println pool+".PerformanceStats.Pool.Total_MBps="+Total_MBps
				println pool+".PerformanceStats.Pool.Read_Ops="+Read_Ops
				println pool+".PerformanceStats.Pool.Write_Ops="+Write_Ops
				println pool+".PerformanceStats.Pool.Total_Ops="+Total_Ops
				println pool+".PerformanceStats.Pool.Read_Latency="+Read_Latency
				println pool+".PerformanceStats.Pool.Write_Latency="+Write_Latency
				println pool+".PerformanceStats.Pool.Average_Latency="+Average_Latency
			}
		}
	}
	return(0);
}

//function to perform API request
def APIrequest(endpoint_url,auth,method, pool_name="", post_reply=false){
	// HTTP Get
	def trustAllCerts = [
		new X509TrustManager() {
			public X509Certificate[] getAcceptedIssuers() {
				return null
			}

			public void checkServerTrusted(X509Certificate[] certs, String authType) throws CertificateException {
			}

			public void checkClientTrusted(X509Certificate[] certs, String authType) throws CertificateException {
			}
		}
	] as TrustManager[] 


	SSLContext sc = SSLContext.getInstance("SSL");
	sc.init(null, trustAllCerts, new SecureRandom());
	CloseableHttpClient httpclient = HttpClients.custom().setSSLHostnameVerifier(NoopHostnameVerifier.INSTANCE).setSslcontext(sc).build();

	if(method=="get"){
		httpGet = new HttpGet(endpoint_url); //SIMPLE GET - Without Params
		httpGet.addHeader("content-type", "application/json"); //GET header
		httpGet.addHeader("Authorization", "Basic "+auth); //GET header
		response = httpclient.execute(httpGet); //GET response
	}

	if(method=="post"){
		httpPost = new HttpPost(endpoint_url);
		httpPost.addHeader("content-type", "application/json"); //POST header
		httpPost.addHeader("Authorization", "Basic "+auth); //POST header

		json = '['+pool_name+']'
		entity = new StringEntity(json);
		httpPost.setEntity(entity);//POST Entity (params)

		//response = httpclient.execute(httpGet); //GET response
		response = httpclient.execute(httpPost); //POST response
	}

	responseBody = EntityUtils.toString(response.getEntity());
	code = response.getStatusLine().getStatusCode();

	httpclient.close();

	if(code==200){
		if(method=="get"){
			JSONArray response_ob = new JSONArray(responseBody);
			return response_ob;//return response
		}

		if(method=="post"){
			if(post_reply==false){
				JSONArray response_ob = new JSONArray(responseBody);
				return response_ob;//return response
			}else{
				reponseBody_raw = "["+responseBody+"]" //ADD [] to expression (otherwise JSONArray fails)
				JSONArray response_ob = new JSONArray(reponseBody_raw);
				return response_ob;//return response
			}
		}
	}else{
		return(404);
	}
}

//according to :
//https://www.logicmonitor.com/support/logicmodules/datasources/active-discovery/script-active-discovery
//active discovery WILDVALUE cannot contain  ['=',':','\','#','space'] characters
//the function below will get rid of those special characters if they exist
def SpecialCharacterCheck(value){
	//special characters not allowed in ActiveDiscovery
	def specialCharacters = ~/\=|\:|\\|\#|\s/

	//replace the special character by nothing & return the 'new' service name
	value=value.replaceAll(specialCharacters, '')
	//println(service); //DEBUG

	return value
}
